# Multi-dimensional scoring with floor thresholds
from dataclasses import dataclass
from typing import Dict, List

@dataclass
class DimensionSpec:
    name: str
    weight: float
    pass_floor: float  # Minimum score for this dimension, regardless of aggregate
    description: str

# Business-context-specific rubric for a fintech code reviewer
FINTECH_RUBRIC = [
    DimensionSpec("correctness",  0.30, 75.0, "Meets all functional requirements"),
    DimensionSpec("security",     0.40, 85.0, "No injection, auth bypass, or secret exposure"),
    DimensionSpec("auditability", 0.20, 70.0, "All financial ops logged with traceability"),
    DimensionSpec("style",        0.10, 50.0, "Consistent with codebase conventions"),
]

@dataclass
class MultiDimScore:
    dimension_scores: Dict[str, float]
    weighted_aggregate: float
    failed_floors: List[str]
    blocking_issues: List[str]
    advisory_issues: List[str]

    @property
    def passes(self) -> bool:
        return self.weighted_aggregate >= 80.0 and len(self.failed_floors) == 0

    def to_generator_feedback(self) -> str:
        lines = ["=== Evaluation Results ==="]
        lines.append(f"Aggregate score: {self.weighted_aggregate:.1f}/100 ({'PASS' if self.passes else 'FAIL'})")
        lines.append("\nDimension breakdown:")
        for dim, score in self.dimension_scores.items():
            status = "pass" if score >= 70 else "FAIL"
            lines.append(f"  [{status}] {dim}: {score:.0f}/100")
        if self.failed_floors:
            lines.append(f"\nDimensions failing floor threshold (MUST fix): {', '.join(self.failed_floors)}")
        if self.blocking_issues:
            lines.append("\nBlocking issues (must fix to pass):")
            for issue in self.blocking_issues:
                lines.append(f"  - {issue}")
        if self.advisory_issues:
            lines.append("\nAdvisory issues (improve if possible):")
            for issue in self.advisory_issues[:3]:
                lines.append(f"  - {issue}")
        return "\n".join(lines)

def compute_score(raw_scores: Dict[str, float], rubric: List[DimensionSpec]) -> MultiDimScore:
    weighted = sum(raw_scores.get(d.name, 0) * d.weight for d in rubric)
    failed_floors = [d.name for d in rubric if raw_scores.get(d.name, 0) < d.pass_floor]
    return MultiDimScore(
        dimension_scores=raw_scores,
        weighted_aggregate=weighted,
        failed_floors=failed_floors,
        blocking_issues=[],
        advisory_issues=[],
    )
